  1	import * as React from 'react';
  2	import { connect } from 'react-redux';
  3	import { CopyToClipboard } from 'react-copy-to-clipboard';
  4	import { serverConfig } from '../../config';
  5	import { ComputedServerConfig } from '../../config/ServerConfig';
  6	import { KialiAppState } from '../../store/Store';
  7	import {
  8	  Alert,
  9	  AlertActionCloseButton,
 10	  AlertVariant,
 11	  Button,
 12	  ButtonVariant,
 13	  Modal,
 14	  ModalVariant,
 15	  Tab
 16	} from '@patternfly/react-core';
 17	import { aceOptions, yamlDumpOptions } from '../../types/IstioConfigDetails';
 18	import AceEditor from 'react-ace';
 19	import { ParameterizedTabs } from '../Tab/Tabs';
 20	import { AuthConfig } from '../../types/Auth';
 21	import { authenticationConfig } from '../../config/AuthenticationConfig';
 22	import { basicTabStyle } from 'styles/TabStyles';
 23	import { istioAceEditorStyle } from 'styles/AceEditorStyle';
 24	import { Theme } from 'types/Common';
 25	import { kialiStyle } from 'styles/StyleUtils';
 26	import ReactAce from 'react-ace/lib/ace';
 27	import { classes } from 'typestyle';
 28	import { usePreviousValue } from 'utils/ReactUtils';
 29	import { ConfigTable } from 'components/Table/ConfigTable';
 30	import { useKialiTranslation } from 'utils/I18nUtils';
 31	import { download } from 'utils/Common';
 32	import { dump } from 'js-yaml';
 33	import { getAllPerfStats } from '../../utils/PerformanceUtils';
 34	
 35	enum CopyStatus {
 36	  NOT_COPIED, // We haven't copied the current output
 37	  COPIED, // Current output is in the clipboard
 38	  OLD_COPY // We copied the prev output, but there are changes in the KialiAppState
 39	}
 40	
 41	type ReduxProps = {
 42	  appState: KialiAppState;
 43	};
 44	
 45	type DebugInformationProps = ReduxProps & {
 46	  isOpen: boolean;
 47	  onClose: () => void;
 48	};
 49	
 50	type DebugInformationData = {
 51	  backendConfigs: {
 52	    authenticationConfig: AuthConfig;
 53	    computedServerConfig: ComputedServerConfig;
 54	  };
 55	  currentURL: string;
 56	  reduxState: KialiAppState;
 57	};
 58	
 59	// Will be shown in Kiali Config and hidden in Additional state
 60	const propsToShow = [
 61	  'authStrategy',
 62	  'clusters',
 63	  'clusterWideAccess',
 64	  'gatewayAPIClasses',
 65	  'gatewayAPIEnabled',
 66	  'istioAnnotationsAction',
 67	  'istioConfigMap',
 68	  'istioIdentityDomain',
 69	  'istioInjectionAction',
 70	  'istioNamespace',
 71	  'istioStatusEnabled',
 72	  'logLevel'
 73	];
 74	
 75	// This should include anything that can not be stringified to JSON
 76	const propsToPatch = ['cyRef', 'summaryTarget', 'target', 'token', 'username'];
 77	
 78	const defaultTab = 'kialiConfig';
 79	
 80	const tabIndex: { [tab: string]: number } = {
 81	  kialiConfig: 0,
 82	  additionalState: 1,
 83	  perfData: 2
 84	};
 85	
 86	const modalStyle = kialiStyle({
 87	  overflowY: 'hidden',
 88	  $nest: {
 89	    '& .pf-v6-c-tab-content': {
 90	      height: '530px',
 91	      overflowY: 'auto'
 92	    }
 93	  }
 94	});
 95	
 96	const tabStyle = kialiStyle({
 97	  $nest: {
 98	    '&& .pf-v6-c-tabs__list': {
 99	      marginLeft: 0
100	    }
101	  }
102	});
103	
104	const spanStyle = kialiStyle({
105	  display: 'inline-block',
106	  marginBottom: '0.25rem',
107	  marginTop: '0.25rem'
108	});
109	
110	const DebugInformationComponent: React.FC<DebugInformationProps> = (props: DebugInformationProps) => {
111	  const [config, setConfig] = React.useState({});
112	  const [copyStatus, setCopyStatus] = React.useState(CopyStatus.NOT_COPIED);
113	  const [currentTab, setCurrentTab] = React.useState(defaultTab);
114	
115	  const aceEditorRef = React.useRef<ReactAce | null>(null);
116	
117	  const { t } = useKialiTranslation();
118	
119	  React.useEffect(() => {
120	    let kialiConfig = {};
121	
122	    for (const key in serverConfig) {
123	      if (propsToShow.includes(key)) {
124	        kialiConfig[key] = serverConfig[key];
125	      }
126	    }
127	    // Order config items
128	    kialiConfig = Object.keys(kialiConfig)
129	      .sort()
130	      .reduce((obj, key) => {
131	        obj[key] = kialiConfig[key];
132	        return obj;
133	      }, {});
134	
135	    setConfig(kialiConfig);
136	  }, []);
137	
138	  const { appState, isOpen } = props;
139	
140	  const prevAppState = usePreviousValue(appState);
141	
142	  React.useEffect(() => {
143	    if (prevAppState !== appState && copyStatus === CopyStatus.COPIED) {
144	      setCopyStatus(CopyStatus.OLD_COPY);
145	    }
146	  }, [prevAppState, appState, copyStatus]);
147	
148	  React.useEffect(() => {
149	    if (isOpen) {
150	      setCopyStatus(CopyStatus.NOT_COPIED);
151	      setCurrentTab(defaultTab);
152	    }
153	  }, [isOpen]);
154	
155	  const copyCallback = (_text: string, result: boolean): void => {
156	    setCopyStatus(result ? CopyStatus.COPIED : CopyStatus.NOT_COPIED);
157	  };
158	
159	  const downloadsMap: { [key: string]: string } = {
160	    kialiConfig: 'kiali_config.yaml',
161	    additionalState: 'additional_state.yaml',
162	    perfData: 'perf_data.yaml'
163	  };
164	
165	  const downloadFile = (): void => {
166	    const fileName = `debug_${downloadsMap[currentTab]}`;
167	
168	    download(copyText, fileName);
169	  };
170	
171	  const hideAlert = (): void => {
172	    setCopyStatus(CopyStatus.NOT_COPIED);
173	  };
174	
175	  const parseConfig = (key: string, value: unknown): unknown | null => {
176	    // We have to patch some runtime properties  we don't want to serialize
177	    if (propsToPatch.includes(key)) {
178	      return null;
179	    }
180	
181	    return value;
182	  };
183	
184	  // Properties shown in Kiali Config are not shown again in Additional State
185	  const filterDebugInformation = (info: DebugInformationData): DebugInformationData => {
186	    if (info !== null) {
187	      for (const [key] of Object.entries(info)) {
188	        if (propsToShow.includes(key)) {
189	          delete info[key];
190	          continue;
191	        }
192	      }
193	    }
194	
195	    return info;
196	  };
197	
198	  if (!props.isOpen) {
199	    return null;
200	  }
201	
202	  let debugInformation: DebugInformationData = {
203	    backendConfigs: {
204	      authenticationConfig: authenticationConfig,
205	      computedServerConfig: serverConfig
206	    },
207	    currentURL: window.location.href,
208	    reduxState: props.appState
209	  };
210	
211	  debugInformation = filterDebugInformation(debugInformation);
212	
213	  // skip invalid regex not allowed by js-yaml dump
214	  const debugInformationText = dump(debugInformation, {
215	    noRefs: true,
216	    replacer: parseConfig,
217	    skipInvalid: true,
218	    ...yamlDumpOptions
219	  });
220	
221	  const perfMeasurements = dump(getAllPerfStats(), {
222	    noRefs: true,
223	    replacer: parseConfig,
224	    skipInvalid: true,
225	    ...yamlDumpOptions
226	  });
227	
228	  const copyTextMap: { [key: string]: string } = {
229	    kialiConfig: dump(config, yamlDumpOptions),
230	    additionalState: debugInformationText,
231	    perfData: perfMeasurements
232	  };
233	
234	  const copyText = copyTextMap[currentTab];
235	
236	  const renderTabs = (): React.ReactNode[] => {
237	    const kialiConfig = (
238	      <Tab eventKey={0} title={t('Kiali Config')} key="kialiConfig">
239	        <ConfigTable label={t('Debug Information')} configData={config} width="30%" />
240	      </Tab>
241	    );
242	
243	    const theme = props.appState.globalState.theme;
244	
245	    const additionalState = (
246	      <Tab eventKey={1} title={t('Additional State')} key="additionalState">
247	        <span className={spanStyle}>{t('Please include this information when opening a bug:')}</span>
248	        <AceEditor
249	          ref={aceEditorRef}
250	          mode="yaml"
251	          theme={theme === Theme.DARK ? 'twilight' : 'eclipse'}
252	          width="100%"
253	          className={istioAceEditorStyle}
254	          wrapEnabled={true}
255	          readOnly={true}
256	          setOptions={aceOptions ?? { foldStyle: 'markbegin' }}
257	          value={debugInformationText}
258	        />
259	      </Tab>
260	    );
261	
262	    const perfData = (
263	      <Tab eventKey={2} title={t('Performance Measurements')} key="perfData">
264	        <span className={spanStyle}>
265	          {t('For Performance issues troubleshooting, remove sensitive data before posting:')}
266	        </span>
267	        <AceEditor
268	          ref={aceEditorRef}
269	          mode="yaml"
270	          theme={theme === Theme.DARK ? 'twilight' : 'eclipse'}
271	          width="100%"
272	          className={istioAceEditorStyle}
273	          wrapEnabled={true}
274	          readOnly={true}
275	          setOptions={aceOptions ?? { foldStyle: 'markbegin' }}
276	          value={perfMeasurements}
277	        />
278	      </Tab>
279	    );
280	    return [kialiConfig, additionalState, perfData];
281	  };
282	
283	  return (
284	    <Modal
285	      className={modalStyle}
286	      variant={ModalVariant.medium}
287	      isOpen={props.isOpen}
288	      onClose={props.onClose}
289	      title={t('Debug information')}
290	      actions={[
291	        <Button key="close" onClick={props.onClose}>
292	          {t('Close')}
293	        </Button>,
294	
295	        <CopyToClipboard key="copy" onCopy={copyCallback} text={copyText}>
296	          <Button variant={ButtonVariant.secondary}>{t('Copy')}</Button>
297	        </CopyToClipboard>,
298	
299	        <Button key="download" variant={ButtonVariant.secondary} onClick={downloadFile}>
300	          {t('Download')}
301	        </Button>
302	      ]}
303	    >
304	      {copyStatus === CopyStatus.COPIED && (
305	        <Alert
306	          style={{ marginBottom: '20px' }}
307	          title={t('Debug information has been copied to your clipboard.')}
308	          variant={AlertVariant.success}
309	          isInline={true}
310	          actionClose={<AlertActionCloseButton onClose={hideAlert} />}
311	        />
312	      )}
313	
314	      {copyStatus === CopyStatus.OLD_COPY && (
315	        <Alert
316	          style={{ marginBottom: '20px' }}
317	          title={t(
318	            'Debug information was copied to your clipboard, but is outdated now. It could be caused by new data received by auto refresh timers.'
319	          )}
320	          variant={AlertVariant.warning}
321	          isInline={true}
322	          actionClose={<AlertActionCloseButton onClose={hideAlert} />}
323	        />
324	      )}
325	
326	      <ParameterizedTabs
327	        id="basic-tabs"
328	        className={classes(basicTabStyle, tabStyle)}
329	        onSelect={tabValue => {
330	          setCurrentTab(tabValue);
331	          hideAlert();
332	        }}
333	        tabMap={tabIndex}
334	        defaultTab={defaultTab}
335	        activeTab={currentTab}
336	        mountOnEnter={true}
337	        unmountOnExit={true}
338	      >
339	        {renderTabs()}
340	      </ParameterizedTabs>
341	    </Modal>
342	  );
343	};
344	
345	const mapStateToProps = (state: KialiAppState): ReduxProps => ({
346	  appState: state
347	});
348	
349	export const DebugInformation = connect(mapStateToProps)(DebugInformationComponent);

