 3	import { location, router } from '../../app/History';
 4	import { kialiStyle } from 'styles/StyleUtils';
 5	import { PFColors } from 'components/Pf/PfColors';
 6	import { classes } from 'typestyle';
 7	
 8	type TabsProps = {
 9	  activeTab: string;
10	  className?: string;
