 31	import { usePreviousValue } from 'utils/ReactUtils';
 32	import { ConfigTable } from 'components/Table/ConfigTable';
 33	import { useKialiTranslation } from 'utils/I18nUtils';
 34	import { download } from 'utils/Common';
 35	import { dump } from 'js-yaml';
 36	import { getAllPerfStats } from '../../utils/PerformanceUtils';
 37	
 38	enum CopyStatus {
 39	  NOT_COPIED, // We haven't copied the current output
 40	  COPIED, // Current output is in the clipboard
 41	  OLD_COPY // We copied the prev output, but there are changes in the KialiAppState
 42	}
 43	
 44	type ReduxProps = {
 45	  appState: KialiAppState;
 46	};
 47	
 48	type DebugInformationProps = ReduxProps & {
 49	  isOpen: boolean;
 50	  onClose: () => void;
 51	};
 52	
 53	type DebugInformationData = {
 54	  backendConfigs: {
 55	    authenticationConfig: AuthConfig;
 56	    computedServerConfig: ComputedServerConfig;
 57	  };
 58	  currentURL: string;
 59	  reduxState: KialiAppState;
 60	};
 61	
 62	// Will be shown in Kiali Config and hidden in Additional state
 63	const propsToShow = [
 64	  'authStrategy',
 65	  'clusters',
 66	  'clusterWideAccess',
 67	  'gatewayAPIClasses',
 68	  'gatewayAPIEnabled',
 69	  'istioAnnotationsAction',
 70	  'istioConfigMap',
 71	  'istioIdentityDomain',
 72	  'istioInjectionAction',
 73	  'istioNamespace',
 74	  'istioStatusEnabled',
 75	  'logLevel'
 76	];
 77	
 78	// This should include anything that can not be stringified to JSON
 79	const propsToPatch = ['cyRef', 'summaryTarget', 'target', 'token', 'username'];
 80	
 81	const defaultTab = 'kialiConfig';
 82	
 83	const tabIndex: { [tab: string]: number } = {
 84	  kialiConfig: 0,
 85	  additionalState: 1,
 86	  perfData: 2
 87	};
 88	
 89	const modalStyle = kialiStyle({
 90	  overflowY: 'hidden',
 91	  $nest: {
 92	    '& .pf-v6-c-tab-content': {
 93	      height: '530px',
 94	      overflowY: 'auto'
 95	    }
 96	  }
 97	});
 98	
 99	const tabStyle = kialiStyle({
100	  $nest: {
101	    '&& .pf-v6-c-tabs__list': {
102	      marginLeft: 0
103	    }
104	  }
105	});
106	
107	const spanStyle = kialiStyle({
108	  display: 'inline-block',
109	  marginBottom: '0.25rem',
110	  marginTop: '0.25rem'
111	});
112	
113	const DebugInformationComponent: React.FC<DebugInformationProps> = (props: DebugInformationProps) => {
114	  const [config, setConfig] = React.useState({});
115	  const [copyStatus, setCopyStatus] = React.useState(CopyStatus.NOT_COPIED);
116	  const [currentTab, setCurrentTab] = React.useState(defaultTab);
117	
118	  const aceEditorRef = React.useRef<ReactAce | null>(null);
119	
120	  const { t } = useKialiTranslation();
121	
122	  React.useEffect(() => {
123	    let kialiConfig = {};
124	
125	    for (const key in serverConfig) {
126	      if (propsToShow.includes(key)) {
127	        kialiConfig[key] = serverConfig[key];
128	      }
129	    }
130	    // Order config items
131	    kialiConfig = Object.keys(kialiConfig)
132	      .sort()
133	      .reduce((obj, key) => {
134	        obj[key] = kialiConfig[key];
135	        return obj;
136	      }, {});
137	
138	    setConfig(kialiConfig);
139	  }, []);
140	
141	  const { appState, isOpen } = props;
142	
143	  const prevAppState = usePreviousValue(appState);
144	
145	  React.useEffect(() => {
146	    if (prevAppState !== appState && copyStatus === CopyStatus.COPIED) {
147	      setCopyStatus(CopyStatus.OLD_COPY);
148	    }
149	  }, [prevAppState, appState, copyStatus]);
150	
151	  React.useEffect(() => {
152	    if (isOpen) {
153	      setCopyStatus(CopyStatus.NOT_COPIED);
154	      setCurrentTab(defaultTab);
155	    }
156	  }, [isOpen]);
157	
158	  const copyCallback = (_text: string, result: boolean): void => {
159	    setCopyStatus(result ? CopyStatus.COPIED : CopyStatus.NOT_COPIED);
160	  };
161	
162	  const downloadsMap: { [key: string]: string } = {
163	    kialiConfig: 'kiali_config.yaml',
164	    additionalState: 'additional_state.yaml',
165	    perfData: 'perf_data.yaml'
166	  };
167	
168	  const downloadFile = (): void => {
169	    const fileName = `debug_${downloadsMap[currentTab]}`;
170	
171	    download(copyText, fileName);
172	  };
173	
174	  const hideAlert = (): void => {
175	    setCopyStatus(CopyStatus.NOT_COPIED);
176	  };
177	
178	  const parseConfig = (key: string, value: unknown): unknown | null => {
179	    // We have to patch some runtime properties  we don't want to serialize
180	    if (propsToPatch.includes(key)) {
181	      return null;
182	    }
183	
184	    return value;
185	  };
186	
187	  // Properties shown in Kiali Config are not shown again in Additional State
188	  const filterDebugInformation = (info: DebugInformationData): DebugInformationData => {
189	    if (info !== null) {
190	      for (const [key] of Object.entries(info)) {
191	        if (propsToShow.includes(key)) {
192	          delete info[key];
193	          continue;
194	        }
195	      }
196	    }
197	
198	    return info;
199	  };
200	
201	  if (!props.isOpen) {
202	    return null;
203	  }
204	
205	  let debugInformation: DebugInformationData = {
206	    backendConfigs: {
207	      authenticationConfig: authenticationConfig,
208	      computedServerConfig: serverConfig
209	    },
210	    currentURL: window.location.href,
211	    reduxState: props.appState
212	  };
213	
214	  debugInformation = filterDebugInformation(debugInformation);
215	
216	  // skip invalid regex not allowed by js-yaml dump
217	  const debugInformationText = dump(debugInformation, {
218	    noRefs: true,
219	    replacer: parseConfig,
220	    skipInvalid: true,
221	    ...yamlDumpOptions
222	  });
223	
224	  const perfMeasurements = dump(getAllPerfStats(), {
225	    noRefs: true,
226	    replacer: parseConfig,
227	    skipInvalid: true,
228	    ...yamlDumpOptions
229	  });
230	
231	  const copyTextMap: { [key: string]: string } = {
232	    kialiConfig: dump(config, yamlDumpOptions),
233	    additionalState: debugInformationText,
234	    perfData: perfMeasurements
235	  };
236	
237	  const copyText = copyTextMap[currentTab];
238	
239	  const renderTabs = (): React.ReactNode[] => {
240	    const kialiConfig = (
241	      <Tab eventKey={0} title={t('Kiali Config')} key="kialiConfig">
242	        <ConfigTable label={t('Debug Information')} configData={config} width="30%" />
243	      </Tab>
244	    );
245	
246	    const theme = props.appState.globalState.theme;
247	
248	    const additionalState = (
249	      <Tab eventKey={1} title={t('Additional State')} key="additionalState">
250	        <span className={spanStyle}>{t('Please include this information when opening a bug:')}</span>
251	        <AceEditor
252	          ref={aceEditorRef}
253	          mode="yaml"
254	          theme={theme === Theme.DARK ? 'twilight' : 'eclipse'}
255	          width="100%"
256	          className={istioAceEditorStyle}
257	          wrapEnabled={true}
258	          readOnly={true}
259	          setOptions={aceOptions ?? { foldStyle: 'markbegin' }}
260	          value={debugInformationText}
261	        />
262	      </Tab>
263	    );
264	
265	    const perfData = (
266	      <Tab eventKey={2} title={t('Performance Measurements')} key="perfData">
267	        <span className={spanStyle}>
268	          {t('For Performance issues troubleshooting, remove sensitive data before posting:')}
269	        </span>
270	        <AceEditor
271	          ref={aceEditorRef}
272	          mode="yaml"
273	          theme={theme === Theme.DARK ? 'twilight' : 'eclipse'}
274	          width="100%"
275	          className={istioAceEditorStyle}
276	          wrapEnabled={true}
277	          readOnly={true}
278	          setOptions={aceOptions ?? { foldStyle: 'markbegin' }}
279	          value={perfMeasurements}
280	        />
281	      </Tab>
282	    );
283	    return [kialiConfig, additionalState, perfData];
284	  };
285	
286	  return (
287	    <Modal
288	      className={modalStyle}
289	      variant={ModalVariant.medium}
290	      isOpen={props.isOpen}
291	      onClose={props.onClose}
292	    >
293	      <ModalHeader title={t('Debug information')} />
294	      <ModalBody>
295	        {copyStatus === CopyStatus.COPIED && (
296	          <Alert
297	            style={{ marginBottom: '20px' }}
298	            title={t('Debug information has been copied to your clipboard.')}
299	            variant={AlertVariant.success}
300	            isInline={true}
301	            actionClose={<AlertActionCloseButton onClose={hideAlert} />}
302	          />
303	        )}
304	
305	        {copyStatus === CopyStatus.OLD_COPY && (
306	          <Alert
307	            style={{ marginBottom: '20px' }}
308	            title={t(
309	              'Debug information was copied to your clipboard, but is outdated now. It could be caused by new data received by auto refresh timers.'
310	            )}
311	            variant={AlertVariant.warning}
312	            isInline={true}
313	            actionClose={<AlertActionCloseButton onClose={hideAlert} />}
314	          />
315	        )}
316	
317	        <ParameterizedTabs
318	          id="basic-tabs"
319	          className={classes(basicTabStyle, tabStyle)}
320	          onSelect={tabValue => {
321	            setCurrentTab(tabValue);
322	            hideAlert();
323	          }}
324	          tabMap={tabIndex}
325	          defaultTab={defaultTab}
326	          activeTab={currentTab}
327	          mountOnEnter={true}
328	          unmountOnExit={true}
329	        >
330	          {renderTabs()}
331	        </ParameterizedTabs>
332	      </ModalBody>
333	      <ModalFooter>
334	        <Button key="close" onClick={props.onClose}>
335	          {t('Close')}
336	        </Button>
337	
338	        <CopyToClipboard key="copy" onCopy={copyCallback} text={copyText}>
339	          <Button variant={ButtonVariant.secondary}>{t('Copy')}</Button>
340	        </CopyToClipboard>
341	
342	        <Button key="download" variant={ButtonVariant.secondary} onClick={downloadFile}>
343	          {t('Download')}
344	        </Button>
345	      </ModalFooter>
346	    </Modal>
347	  );
348	};
349	
350	const mapStateToProps = (state: KialiAppState): ReduxProps => ({
351	  appState: state
352	});
353	
354	export const DebugInformation = connect(mapStateToProps)(DebugInformationComponent);

