117	
118	  const aceEditorRef = React.useRef<ReactAce | null>(null);
119	
120	  const { t } = useKialiTranslation();
121	
122	  React.useEffect(() => {
123	    let kialiConfig = {};
124	
125	    for (const key in serverConfig) {
126	      if (propsToShow.includes(key)) {
127	        kialiConfig[key] = serverConfig[key];
128	      }
129	    }
130	    // Order config items
131	    kialiConfig = Object.keys(kialiConfig)
132	      .sort()
133	      .reduce((obj, key) => {
134	        obj[key] = kialiConfig[key];
135	        return obj;
136	      }, {});
137	
138	    setConfig(kialiConfig);
139	  }, []);
140	
141	  const { appState, isOpen } = props;
142	
143	  const prevAppState = usePreviousValue(appState);
144	
145	  React.useEffect(() => {
146	    if (prevAppState !== appState && copyStatus === CopyStatus.COPIED) {
147	      setCopyStatus(CopyStatus.OLD_COPY);
148	    }
149	  }, [prevAppState, appState, copyStatus]);
150	
151	  React.useEffect(() => {
152	    if (isOpen) {
153	      setCopyStatus(CopyStatus.NOT_COPIED);
154	      setCurrentTab(defaultTab);
155	    }
156	  }, [isOpen]);
