245	
246	    const theme = props.appState.globalState.theme;
247	
248	    const additionalState = (
249	      <Tab eventKey={1} title={t('Additional State')} key="additionalState">
250	        <span className={spanStyle}>{t('Please include this information when opening a bug:')}</span>
251	        <AceEditor
252	          ref={aceEditorRef}
253	          mode="yaml"
254	          theme={theme === Theme.DARK ? 'twilight' : 'eclipse'}
255	          width="100%"
256	          className={istioAceEditorStyle}
