267	        <span className={spanStyle}>
268	          {t('For Performance issues troubleshooting, remove sensitive data before posting:')}
269	        </span>
270	        <AceEditor
271	          ref={aceEditorRef}
272	          mode="yaml"
273	          theme={theme === Theme.DARK ? 'twilight' : 'eclipse'}
274	          width="100%"
275	          className={istioAceEditorStyle}
276	          wrapEnabled={true}
277	          readOnly={true}
278	          setOptions={aceOptions ?? { foldStyle: 'markbegin' }}
279	          value={perfMeasurements}
280	        />
281	      </Tab>
282	    );
283	    return [kialiConfig, additionalState, perfData];
284	  };
285	
286	  return (
287	    <Modal
288	      className={modalStyle}
289	      variant={ModalVariant.medium}
290	      isOpen={props.isOpen}
291	      onClose={props.onClose}
292	    >
293	      <ModalHeader title={t('Debug information')} />
294	      <ModalBody>
295	        {copyStatus === CopyStatus.COPIED && (
296	          <Alert
297	            style={{ marginBottom: '20px' }}
298	            title={t('Debug information has been copied to your clipboard.')}
299	            variant={AlertVariant.success}
300	            isInline={true}
301	            actionClose={<AlertActionCloseButton onClose={hideAlert} />}
302	          />
303	        )}
304	
305	        {copyStatus === CopyStatus.OLD_COPY && (
306	          <Alert
307	            style={{ marginBottom: '20px' }}
308	            title={t(
309	              'Debug information was copied to your clipboard, but is outdated now. It could be caused by new data received by auto refresh timers.'
310	            )}
311	            variant={AlertVariant.warning}
312	            isInline={true}
313	            actionClose={<AlertActionCloseButton onClose={hideAlert} />}
314	          />
315	        )}
316	
317	        <ParameterizedTabs
318	          id="basic-tabs"
319	          className={classes(basicTabStyle, tabStyle)}
320	          onSelect={tabValue => {
