337	
338	        <CopyToClipboard key="copy" onCopy={copyCallback} text={copyText}>
339	          <Button variant={ButtonVariant.secondary}>{t('Copy')}</Button>
340	        </CopyToClipboard>
341	
342	        <Button key="download" variant={ButtonVariant.secondary} onClick={downloadFile}>
343	          {t('Download')}
344	        </Button>
345	      </ModalFooter>
346	    </Modal>
347	  );
348	};
